"use client";
import { useState, useEffect } from "react"; // เพิ่ม useEffect
import { useRouter } from "next/navigation";
import { useSession } from "next-auth/react";
import Link from "next/link";

export default function NewRecordPage() {
  const { data: session, status } = useSession();
  const router = useRouter();

  // จัดการการเปลี่ยนหน้าผ่าน useEffect เพื่อป้องกัน Error ระหว่าง Render
  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/login");
    }
  }, [status, router]);

  // ตัวแปรเก็บข้อมูลอาการทางกายภาพ
  const [neckPain, setNeckPain] = useState(false);
  const [backPain, setBackPain] = useState(false);
  const [eyeStrain, setEyeStrain] = useState(false);
  const [wristPain, setWristPain] = useState(false);
  const [headache, setHeadache] = useState(false);
  const [fingerNumbness, setFingerNumbness] = useState(false);
  const [legNumbness, setLegNumbness] = useState(false);
  
  const [tookBreaks, setTookBreaks] = useState(false);
  const [stressLevel, setStressLevel] = useState(1);
  const [note, setNote] = useState("");

  // แสดงสถานะการโหลดข้อมูล
  if (status === "loading") {
    return (
      <div className="container" style={{ marginTop: '40px', textAlign: 'center' }}>
        <p className="muted">กำลังตรวจสอบสิทธิ์การใช้งาน...</p>
      </div>
    );
  }

  // หากไม่มีเซสชัน ให้ส่งกลับเป็น null ระหว่างรอ useEffect ทำงาน
  if (!session) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    try {
      const response = await fetch("/api/records", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          neckPain, backPain, eyeStrain, wristPain,
          headache, fingerNumbness, legNumbness,
          tookBreaks, stressLevel, note
        }),
      });

      if (response.ok) {
        alert("บันทึกข้อมูลสุขภาพประจำวันเรียบร้อยแล้ว");
        router.push("/records");
        router.refresh();
      } else {
        const errorData = await response.json();
        alert(`เกิดข้อผิดพลาด: ${errorData.error}`);
      }
    } catch (error) {
      alert("ไม่สามารถเชื่อมต่อกับฐานข้อมูลได้");
    }
  };

  return (
    // ... เนื้อหา JSX ส่วนที่เหลือของท่านโอ๊คคงเดิมได้เลยครับ ...
    <section className="container" style={{ maxWidth: '600px', marginTop: '40px' }}>
       {/* UI ฟอร์มบันทึกข้อมูล */}
    </section>
  );
}